import { createContext, useContext, useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Enrollment, UserProgress } from "@/types/learning";
import { toast } from "sonner";

interface EnrollmentContextType {
    enrollments: Enrollment[];
    progress: Record<string, UserProgress[]>; // course_id -> progress[]
    loading: boolean;
    enrollInCourse: (courseId: string) => Promise<void>;
    updateProgress: (courseId: string, moduleId: string, isCompleted: boolean) => Promise<void>;
    checkEnrollment: (courseId: string) => boolean;
    getCourseProgress: (courseId: string) => number;
}

const EnrollmentContext = createContext<EnrollmentContextType | undefined>(undefined);

export function EnrollmentProvider({ children }: { children: React.ReactNode }) {
    const [enrollments, setEnrollments] = useState<Enrollment[]>([]);
    const [progress, setProgress] = useState<Record<string, UserProgress[]>>({});
    const [loading, setLoading] = useState(true);

    const fetchEnrollments = async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) {
            setLoading(false);
            return;
        }

        const { data: enrollData, error } = await supabase
            .from("learning_enrollments")
            .select("*")
            .eq("user_id", user.id);

        if (error) {
            console.error("Error fetching enrollments:", error);
        } else {
            setEnrollments(enrollData || []);
        }

        const { data: progressData } = await supabase
            .from("learning_progress")
            .select("*")
            .eq("user_id", user.id);

        if (progressData) {
            const progressMap: Record<string, UserProgress[]> = {};
            progressData.forEach(p => {
                if (!progressMap[p.course_id]) progressMap[p.course_id] = [];
                progressMap[p.course_id].push(p);
            });
            setProgress(progressMap);
        }

        setLoading(false);
    };

    useEffect(() => {
        fetchEnrollments();
    }, []);

    const enrollInCourse = async (courseId: string) => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) {
            toast.error("You must be logged in to enroll.");
            return;
        }

        // Check if already enrolled locally first
        if (enrollments.some(e => e.course_id === courseId)) {
            toast.info("You are already enrolled in this course.");
            return;
        }

        try {
            const { data, error } = await supabase
                .from("learning_enrollments")
                .upsert(
                    { user_id: user.id, course_id: courseId },
                    { onConflict: "user_id,course_id", ignoreDuplicates: true }
                )
                .select()
                .single();

            if (error) throw error;

            if (data) {
                setEnrollments([...enrollments, data]);
            }
            toast.success("Successfully enrolled!");
        } catch (error) {
            console.error("Enrollment error:", error);
            toast.error("Failed to enroll in course.");
        }
    };

    const updateProgress = async (courseId: string, moduleId: string, isCompleted: boolean) => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        try {
            const { data, error } = await supabase
                .from("learning_progress")
                .upsert({
                    user_id: user.id,
                    course_id: courseId,
                    module_id: moduleId,
                    is_completed: isCompleted,
                    completed_at: isCompleted ? new Date().toISOString() : null
                })
                .select()
                .single();

            if (error) throw error;

            const currentCourseProgress = progress[courseId] || [];
            const updatedCourseProgress = [
                ...currentCourseProgress.filter(p => p.module_id !== moduleId),
                data
            ];

            setProgress({
                ...progress,
                [courseId]: updatedCourseProgress
            });

            // Refetch enrollments so progress % (updated by DB trigger) is correct in UI
            const { data: enrollData } = await supabase
                .from("learning_enrollments")
                .select("*")
                .eq("user_id", user.id);
            if (enrollData) setEnrollments(enrollData);
        } catch (error) {
            console.error("Progress update error:", error);
            toast.error("Failed to update progress.");
        }
    };

    const checkEnrollment = (courseId: string) => {
        return enrollments.some(e => e.course_id === courseId);
    };

    const getCourseProgress = (courseId: string) => {
        const course = enrollments.find(e => e.course_id === courseId);
        return course?.progress || 0;
    };

    return (
        <EnrollmentContext.Provider value={{
            enrollments,
            progress,
            loading,
            enrollInCourse,
            updateProgress,
            checkEnrollment,
            getCourseProgress
        }}>
            {children}
        </EnrollmentContext.Provider>
    );
}

export const useEnrollment = () => {
    const context = useContext(EnrollmentContext);
    if (context === undefined) {
        throw new Error("useEnrollment must be used within an EnrollmentProvider");
    }
    return context;
};

import { createContext, useContext, useEffect, useState, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
    LearningUserStats,
    LearningAchievement,
} from "@/types/learning";
import { ACHIEVEMENT_DEFINITIONS } from "@/lib/gamification";
import { useLearner } from "./LearnerContext";

type GamificationContextType = {
    stats: LearningUserStats | null;
    achievements: LearningAchievement[];
    loading: boolean;
    addXp: (points: number) => Promise<void>;
    recordActivity: () => Promise<void>;
    awardAchievement: (type: keyof typeof ACHIEVEMENT_DEFINITIONS) => Promise<boolean>;
    refresh: () => Promise<void>;
};

const GamificationContext = createContext<GamificationContextType | undefined>(undefined);

const XP_PER_ACTIVITY = 5;

/**
 * Gamification Context — uses learner token ID as the primary identifier.
 * Falls back to Supabase auth user_id for admin users.
 */
export function GamificationProvider({ children }: { children: React.ReactNode }) {
    const { learner, isIdentified } = useLearner();
    const [stats, setStats] = useState<LearningUserStats | null>(null);
    const [achievements, setAchievements] = useState<LearningAchievement[]>([]);
    const [loading, setLoading] = useState(true);

    // Determine which identifier to use for DB queries
    const getIdentifier = useCallback(async (): Promise<{ column: string; value: string } | null> => {
        if (isIdentified && learner) {
            return { column: "learner_token_id", value: learner.id };
        }
        // Fallback: check Supabase auth (for admin users)
        const { data: { user } } = await supabase.auth.getUser();
        if (user) return { column: "user_id", value: user.id };
        return null;
    }, [isIdentified, learner]);

    const fetchData = useCallback(async () => {
        const id = await getIdentifier();
        if (!id) {
            setStats(null);
            setAchievements([]);
            setLoading(false);
            return;
        }

        const [statsRes, achievementsRes] = await Promise.all([
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (supabase.from("learning_user_stats").select("*") as any).eq(id.column, id.value).maybeSingle(),
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            (supabase.from("learning_achievements").select("*") as any).eq(id.column, id.value).order("earned_at", { ascending: false }),
        ]);

        setStats(statsRes.data as LearningUserStats | null);
        setAchievements((achievementsRes.data as LearningAchievement[]) || []);
        setLoading(false);
    }, [getIdentifier]);

    useEffect(() => {
        fetchData(); // eslint-disable-line react-hooks/set-state-in-effect -- async fetch sets state in callback
    }, [fetchData]);

    const addXp = useCallback(async (points: number) => {
        const id = await getIdentifier();
        if (!id) return;

        const { data: existing } = await (supabase
            .from("learning_user_stats")
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            .select("total_xp") as any)
            .eq(id.column, id.value)
            .maybeSingle();

        await supabase.from("learning_user_stats").upsert({
            [id.column]: id.value,
            total_xp: (existing?.total_xp || 0) + points,
            current_streak_days: existing ? undefined : 0,
            updated_at: new Date().toISOString(),
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any, { onConflict: id.column });

        await fetchData();
    }, [getIdentifier, fetchData]);

    const todayStr = () => new Date().toISOString().slice(0, 10);

    const recordActivity = useCallback(async () => {
        const id = await getIdentifier();
        if (!id) return;

        const today = todayStr();
        const { data: existing } = await (supabase
            .from("learning_user_stats")
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            .select("*") as any)
            .eq(id.column, id.value)
            .maybeSingle();

        let newStreak = 1;
        if (existing?.last_activity_date) {
            const last = existing.last_activity_date.toString().slice(0, 10);
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = yesterday.toISOString().slice(0, 10);
            if (last === yesterdayStr) newStreak = (existing.current_streak_days || 0) + 1;
            else if (last !== today) newStreak = 1;
            else newStreak = existing.current_streak_days || 1;
        }

        await supabase.from("learning_user_stats").upsert({
            [id.column]: id.value,
            total_xp: (existing?.total_xp || 0) + XP_PER_ACTIVITY,
            current_streak_days: newStreak,
            last_activity_date: today,
            updated_at: new Date().toISOString(),
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any, { onConflict: id.column });

        await fetchData();
    }, [getIdentifier, fetchData]);

    const awardAchievement = useCallback(async (type: keyof typeof ACHIEVEMENT_DEFINITIONS): Promise<boolean> => {
        const id = await getIdentifier();
        if (!id) return false;

        const def = ACHIEVEMENT_DEFINITIONS[type];
        if (!def) return false;

        // Check if already awarded
        const { data: existing } = await (supabase
            .from("learning_achievements")
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            .select("id") as any)
            .eq(id.column, id.value)
            .eq("achievement_type", type)
            .maybeSingle();

        if (existing) return false;

        try {
            const { data: inserted } = await supabase.from("learning_achievements").insert({
                [id.column]: id.value,
                achievement_type: type,
                points_earned: def.xp,
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
            } as any).select("id").maybeSingle();

            if (inserted) {
                await addXp(def.xp);
            }
            await fetchData();
            return !!inserted;
        } catch {
            return false;
        }
    }, [getIdentifier, addXp, fetchData]);

    return (
        <GamificationContext.Provider
            value={{
                stats,
                achievements,
                loading,
                addXp,
                recordActivity,
                awardAchievement,
                refresh: fetchData,
            }}
        >
            {children}
        </GamificationContext.Provider>
    );
}

export function useGamification() {
    const ctx = useContext(GamificationContext);
    if (ctx === undefined) throw new Error("useGamification must be used within GamificationProvider");
    return ctx;
}

import { createContext, useContext, useEffect, useState, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { generateFingerprint } from "@/lib/fingerprint";

const LEARNER_TOKEN_KEY = "spark_learner_token";

export interface LearnerProfile {
  id: string;
  token: string;
  name: string;
  email: string;
  grade: string;
  phone: string;
  enrollment_id: string | null;
  created_at: string;
}

export interface LearnerCourseEnrollment {
  id: string;
  learner_token_id: string;
  course_id: string;
  enrolled_at: string;
  progress: number;
  completed_at: string | null;
}

export interface LearnerModuleProgress {
  id: string;
  learner_token_id: string;
  course_id: string;
  module_id: string;
  is_completed: boolean;
  completed_at: string | null;
}

interface LearnerContextType {
  learner: LearnerProfile | null;
  loading: boolean;
  enrollments: LearnerCourseEnrollment[];
  progress: Record<string, LearnerModuleProgress[]>;
  isIdentified: boolean;
  enrollInCourse: (courseId: string) => Promise<void>;
  updateModuleProgress: (courseId: string, moduleId: string, isCompleted: boolean) => Promise<void>;
  checkCourseEnrollment: (courseId: string) => boolean;
  getCourseProgress: (courseId: string) => number;
  registerLearner: (data: { name: string; email: string; grade: string; phone: string; enrollmentId?: string }) => Promise<void>;
  refreshEnrollments: () => Promise<void>;
}

const LearnerContext = createContext<LearnerContextType | undefined>(undefined);

export function LearnerProvider({ children }: { children: React.ReactNode }) {
  const [learner, setLearner] = useState<LearnerProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [enrollments, setEnrollments] = useState<LearnerCourseEnrollment[]>([]);
  const [progress, setProgress] = useState<Record<string, LearnerModuleProgress[]>>({});

  // Load learner from localStorage on mount
  useEffect(() => {
    const init = async () => {
      try {
        const savedToken = localStorage.getItem(LEARNER_TOKEN_KEY);
        if (savedToken) {
          const { data, error } = await supabase
            .from("learner_tokens")
            .select("*")
            .eq("token", savedToken)
            .maybeSingle();

          if (data && !error) {
            setLearner(data as LearnerProfile);
            // Update last_seen_at
            await supabase
              .from("learner_tokens")
              .update({ last_seen_at: new Date().toISOString(), browser_fingerprint: generateFingerprint() })
              .eq("id", data.id);
          } else {
            // Token invalid, try fingerprint match
            const fp = generateFingerprint();
            const { data: fpMatch } = await supabase
              .from("learner_tokens")
              .select("*")
              .eq("browser_fingerprint", fp)
              .maybeSingle();

            if (fpMatch) {
              setLearner(fpMatch as LearnerProfile);
              localStorage.setItem(LEARNER_TOKEN_KEY, fpMatch.token);
              await supabase
                .from("learner_tokens")
                .update({ last_seen_at: new Date().toISOString() })
                .eq("id", fpMatch.id);
            }
          }
        } else {
          // No token saved, try fingerprint
          const fp = generateFingerprint();
          const { data: fpMatch } = await supabase
            .from("learner_tokens")
            .select("*")
            .eq("browser_fingerprint", fp)
            .maybeSingle();

          if (fpMatch) {
            setLearner(fpMatch as LearnerProfile);
            localStorage.setItem(LEARNER_TOKEN_KEY, fpMatch.token);
          }
        }
      } catch (err) {
        console.error("Learner init error:", err);
      } finally {
        setLoading(false);
      }
    };
    init();
  }, []);

  // Fetch enrollments when learner is set
  useEffect(() => {
    if (learner) {
      fetchEnrollments();
      fetchProgress();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [learner?.id]);

  const fetchEnrollments = useCallback(async () => {
    if (!learner) return;
    const { data } = await supabase
      .from("learner_course_enrollments")
      .select("*")
      .eq("learner_token_id", learner.id);
    setEnrollments((data as LearnerCourseEnrollment[]) || []);
  }, [learner]);

  const fetchProgress = useCallback(async () => {
    if (!learner) return;
    const { data } = await supabase
      .from("learner_progress")
      .select("*")
      .eq("learner_token_id", learner.id);

    const progressMap: Record<string, LearnerModuleProgress[]> = {};
    (data || []).forEach((p: { course_id: string; [key: string]: unknown }) => {
      if (!progressMap[p.course_id]) progressMap[p.course_id] = [];
      progressMap[p.course_id].push(p as unknown as LearnerModuleProgress);
    });
    setProgress(progressMap);
  }, [learner]);

  const registerLearner = async (data: { name: string; email: string; grade: string; phone: string; enrollmentId?: string }) => {
    const token = crypto.randomUUID();
    const fp = generateFingerprint();

    const { data: newLearner, error } = await supabase
      .from("learner_tokens")
      .insert({
        token,
        browser_fingerprint: fp,
        name: data.name,
        email: data.email.toLowerCase().trim(),
        grade: data.grade,
        phone: data.phone,
        enrollment_id: data.enrollmentId || null,
      })
      .select()
      .single();

    if (error) throw error;
    
    localStorage.setItem(LEARNER_TOKEN_KEY, token);
    setLearner(newLearner as LearnerProfile);
  };

  const enrollInCourse = async (courseId: string) => {
    if (!learner) return;
    const { data, error } = await supabase
      .from("learner_course_enrollments")
      .insert({ learner_token_id: learner.id, course_id: courseId })
      .select()
      .single();

    if (error) {
      if (error.code === "23505") return; // Already enrolled
      throw error;
    }

    setEnrollments((prev) => [...prev, data as LearnerCourseEnrollment]);
  };

  const updateModuleProgress = async (courseId: string, moduleId: string, isCompleted: boolean) => {
    if (!learner) return;

    const { data, error } = await supabase
      .from("learner_progress")
      .upsert({
        learner_token_id: learner.id,
        course_id: courseId,
        module_id: moduleId,
        is_completed: isCompleted,
        completed_at: isCompleted ? new Date().toISOString() : null,
      })
      .select()
      .single();

    if (error) throw error;

    // Update local progress
    const courseProgress = progress[courseId] || [];
    const updated = [
      ...courseProgress.filter((p) => p.module_id !== moduleId),
      data as LearnerModuleProgress,
    ];
    setProgress((prev) => ({ ...prev, [courseId]: updated }));

    // Refetch enrollments to get updated progress %
    await fetchEnrollments();
  };

  const checkCourseEnrollment = (courseId: string) => {
    return enrollments.some((e) => e.course_id === courseId);
  };

  const getCourseProgress = (courseId: string) => {
    const enrollment = enrollments.find((e) => e.course_id === courseId);
    return enrollment?.progress || 0;
  };

  return (
    <LearnerContext.Provider
      value={{
        learner,
        loading,
        enrollments,
        progress,
        isIdentified: !!learner,
        enrollInCourse,
        updateModuleProgress,
        checkCourseEnrollment,
        getCourseProgress,
        registerLearner,
        refreshEnrollments: fetchEnrollments,
      }}
    >
      {children}
    </LearnerContext.Provider>
  );
}

export const useLearner = () => {
  const context = useContext(LearnerContext);
  if (!context) throw new Error("useLearner must be used within LearnerProvider");
  return context;
};

