        if ((event as string) === 'TOKEN_REFRESH_MISSING') {
          console.error('Refresh token missing, forcing logout');
          await supabase.auth.signOut();
          if (mounted) {
            setUser(null);
            setRole(null);
            clearAdminBypass();
            setLoading(false);
          }
          return;
        }

        if (mounted) setUser(session?.user ?? null);

        if (session?.user) {
          // Defer Supabase calls with setTimeout to prevent deadlock
          setTimeout(async () => {
            if (!mounted) return;
            const userRole = await fetchUserRole(session.user.id);
            if (!mounted) return;
            setRole(userRole);
            setAdminBypass(CMS_ACCESS_ROLES.includes(userRole));
            setLoading(false);
          }, 0);
        } else {
          if (mounted) {
            setRole(null);
            clearAdminBypass();
            setLoading(false);
          }
        }
      }
    );

    // Check for existing session
    supabase.auth.getSession().then(async ({ data: { session }, error }) => {
      if (!mounted) return;

      if (error) {
        console.error("Error getting session:", error);
        if (error.message.includes("Refresh Token Not Found") || error.message.includes("Invalid Refresh Token")) {
          await supabase.auth.signOut();
          if (mounted) {
            setUser(null);
            setRole(null);
            clearAdminBypass();
          }
        }
        if (mounted) setLoading(false);
        return;
      }

      if (mounted) setUser(session?.user ?? null);
      if (session?.user) {
        const userRole = await fetchUserRole(session.user.id);
        if (mounted) {
          setRole(userRole);
          setAdminBypass(CMS_ACCESS_ROLES.includes(userRole));
        }
      }
      if (mounted) setLoading(false);
    });

    return () => {
      mounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const hasPermission = (permission: string): boolean => {
    if (!role) return false;
    if (role === 'admin') return true;

    const permissions = ROLE_PERMISSIONS[role] || [];
    return permissions.includes('all') || permissions.includes(permission);
  };

  const canAccessPage = (pagePath: string): boolean => {
    if (!role) return false;
    if (role === 'admin') return true;

    const permission = PAGE_PERMISSION_MAP[pagePath];
    if (!permission) return false;

    return hasPermission(permission);
  };

  const canAccessCMS = (): boolean => {
    return role !== null && CMS_ACCESS_ROLES.includes(role);
  };

  const getRoleBadgeColor = (): string => {
    switch (role) {
      case 'admin':
        return 'bg-destructive/20 text-destructive';
      case 'editor':
        return 'bg-blue-500/20 text-blue-500';
      case 'content_creator':
        return 'bg-green-500/20 text-green-500';
      case 'coordinator':
        return 'bg-orange-500/20 text-orange-500';
      default:
        return 'bg-muted text-muted-foreground';
    }
  };

  const getRoleDisplayName = (): string => {
    if (!role) return 'No Role';
    return role.charAt(0).toUpperCase() + role.slice(1).replace(/_/g, ' ');
  };

  return (
    <RoleContext.Provider
      value={{
        user,
        role,
        loading,
        hasPermission,
        canAccessPage,
        canAccessCMS,
        refreshRole,
        getRoleBadgeColor,
        getRoleDisplayName,
      }}
    >
      {children}
    </RoleContext.Provider>
  );
};

export const useRole = (): RoleContextType => {
  const context = useContext(RoleContext);
  if (context === undefined) {
    throw new Error('useRole must be used within a RoleProvider');
  }
  return context;
};

